                  {['Date', 'Brief Ref', 'Client', 'Court', 'Barrister', 'Matter'].map((h) => (
                    <TableHead key={h} className="text-gray-500 text-xs">
                      {h}
                    </TableHead>
                  ))}
                </TableRow>
              </TableHeader>
              <TableBody>
                {sorted.map((e) => (
