const findLeadByEmail = {
  key: 'find_lead_by_email',
  noun: 'Lead',

  display: {
    label: 'Find Lead by Email',
    description: 'Searches VaultLine for an existing demo lead by email address.',
  },

  operation: {
    inputFields: [
      { key: 'email', label: 'Email Address', type: 'string', required: true },
